import{_ as a,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Apéndice | Tutorial de Clawdbot","description":"Capítulo de apéndice de Clawdbot: referencia completa de configuración, protocolo API WebSocket de Gateway, opciones de despliegue y guía de desarrollo.","frontmatter":{"title":"Apéndice | Tutorial de Clawdbot","sidebarTitle":"Configuración, Despliegue y Desarrollo","subtitle":"Apéndice","description":"Capítulo de apéndice de Clawdbot: referencia completa de configuración, protocolo API WebSocket de Gateway, opciones de despliegue y guía de desarrollo.","tags":[],"order":340},"headers":[],"relativePath":"es/moltbot/moltbot/appendix/index.md","filePath":"es/moltbot/moltbot/appendix/index.md"}'),n={name:"es/moltbot/moltbot/appendix/index.md"};function l(s,e,d,c,t,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="apendice" tabindex="-1">Apéndice <a class="header-anchor" href="#apendice" aria-label="Permalink to &quot;Apéndice&quot;">​</a></h1><p>Este capítulo proporciona documentación de referencia avanzada y recursos de desarrollo para Clawdbot, incluyendo la referencia completa de configuración, especificaciones del protocolo API WebSocket de Gateway, opciones de despliegue y guías de desarrollo.</p><div class="info custom-block"><p class="custom-block-title">Escenarios de uso</p><p>Este capítulo es adecuado para usuarios que necesitan comprender profundamente los mecanismos internos de Clawdbot, realizar configuraciones avanzadas, despliegues o participar en el desarrollo. Si estás empezando, te recomendamos completar primero el capítulo <a href="./../../start/getting-started/">Inicio rápido</a>.</p></div><h2 id="navegacion-de-subpaginas" tabindex="-1">Navegación de subpáginas <a class="header-anchor" href="#navegacion-de-subpaginas" aria-label="Permalink to &quot;Navegación de subpáginas&quot;">​</a></h2><h3 id="referencia-de-configuracion-completa" tabindex="-1"><a href="./config-reference/">Referencia de configuración completa</a> <a class="header-anchor" href="#referencia-de-configuracion-completa" aria-label="Permalink to &quot;[Referencia de configuración completa](./config-reference/)&quot;">​</a></h3><p><strong>Referencia detallada del archivo de configuración</strong> - Cubre todos los elementos de configuración, valores predeterminados y ejemplos. Busca explicaciones completas de configuración para módulos como Gateway, Agent, canales y herramientas.</p><h3 id="protocolo-api-websocket-de-gateway" tabindex="-1"><a href="./api-protocol/">Protocolo API WebSocket de Gateway</a> <a class="header-anchor" href="#protocolo-api-websocket-de-gateway" aria-label="Permalink to &quot;[Protocolo API WebSocket de Gateway](./api-protocol/)&quot;">​</a></h3><p><strong>Documento de especificación del protocolo</strong> - Especificaciones completas del protocolo WebSocket de Gateway, incluyendo definiciones de endpoints, formatos de mensajes, métodos de autenticación y mecanismos de suscripción a eventos. Adecuado para desarrolladores que necesitan personalizar clientes o integrar Gateway.</p><h3 id="opciones-de-despliegue" tabindex="-1"><a href="./deployment/">Opciones de despliegue</a> <a class="header-anchor" href="#opciones-de-despliegue" aria-label="Permalink to &quot;[Opciones de despliegue](./deployment/)&quot;">​</a></h3><p><strong>Guía de métodos de despliegue</strong> - Métodos de despliegue en diferentes plataformas: instalación local, Docker, VPS, Fly.io, Nix, etc. Aprende a ejecutar Clawdbot en varios entornos.</p><h3 id="guia-de-desarrollo" tabindex="-1"><a href="./development/">Guía de desarrollo</a> <a class="header-anchor" href="#guia-de-desarrollo" aria-label="Permalink to &quot;[Guía de desarrollo](./development/)&quot;">​</a></h3><p><strong>Documentación para desarrolladores</strong> - Construcción desde código fuente, desarrollo de plugins, pruebas y proceso de contribuciones. Aprende cómo participar en el desarrollo del proyecto Clawdbot o escribir plugins personalizados.</p><h2 id="recomendaciones-de-ruta-de-aprendizaje" tabindex="-1">Recomendaciones de ruta de aprendizaje <a class="header-anchor" href="#recomendaciones-de-ruta-de-aprendizaje" aria-label="Permalink to &quot;Recomendaciones de ruta de aprendizaje&quot;">​</a></h2><p>Según tus necesidades, elige la ruta de aprendizaje adecuada:</p><h3 id="personal-de-configuracion-y-operaciones" tabindex="-1">Personal de configuración y operaciones <a class="header-anchor" href="#personal-de-configuracion-y-operaciones" aria-label="Permalink to &quot;Personal de configuración y operaciones&quot;">​</a></h3><ol><li>Primero lee la <a href="./config-reference/">Referencia de configuración completa</a> - Comprende todos los elementos configurables</li><li>Consulta las <a href="./deployment/">Opciones de despliegue</a> - Elige el esquema de despliegue adecuado</li><li>Según sea necesario, consulta la documentación de la API WebSocket de Gateway para la integración</li></ol><h3 id="desarrolladores-de-aplicaciones" tabindex="-1">Desarrolladores de aplicaciones <a class="header-anchor" href="#desarrolladores-de-aplicaciones" aria-label="Permalink to &quot;Desarrolladores de aplicaciones&quot;">​</a></h3><ol><li>Lee el <a href="./api-protocol/">Protocolo API WebSocket de Gateway</a> - Comprende los mecanismos del protocolo</li><li>Consulta la <a href="./config-reference/">Referencia de configuración completa</a> - Comprende cómo configurar las funcionalidades relacionadas</li><li>Construye el cliente basándote en ejemplos del protocolo</li></ol><h3 id="desarrolladores-de-plugins-funcionalidades" tabindex="-1">Desarrolladores de plugins/funcionalidades <a class="header-anchor" href="#desarrolladores-de-plugins-funcionalidades" aria-label="Permalink to &quot;Desarrolladores de plugins/funcionalidades&quot;">​</a></h3><ol><li>Lee la <a href="./development/">Guía de desarrollo</a> - Comprende el entorno de desarrollo y el proceso de construcción</li><li>Profundiza en el <a href="./api-protocol/">Protocolo API WebSocket de Gateway</a> - Comprende la arquitectura de Gateway</li><li>Consulta la <a href="./config-reference/">Referencia de configuración completa</a> - Comprende el sistema de configuración</li></ol><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Conocimientos previos</p><p>Antes de profundizar en este capítulo, se recomienda que hayas completado lo siguiente:</p><ul><li>✅ Completado <a href="./../../start/getting-started/">Inicio rápido</a></li><li>✅ Configurado al menos un canal (como <a href="./../../platforms/whatsapp/">WhatsApp</a> o <a href="./../../platforms/telegram/">Telegram</a>)</li><li>✅ Comprendido la configuración básica de modelos de AI (consulta <a href="./../../advanced/models-auth/">Modelos de AI y autenticación</a>)</li><li>✅ Conocimiento básico de archivos de configuración JSON y TypeScript</li></ul></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Después de completar el estudio de este capítulo, puedes:</p><ul><li><strong>Realizar configuraciones avanzadas</strong> - Consulta la <a href="./config-reference/">Referencia de configuración completa</a> para personalizar tu Clawdbot</li><li><strong>Desplegar en producción</strong> - Según las <a href="./deployment/">Opciones de despliegue</a>, elige el esquema de despliegue adecuado</li><li><strong>Desarrollar funcionalidades personalizadas</strong> - Consulta la <a href="./development/">Guía de desarrollo</a> para escribir plugins o contribuir código</li><li><strong>Profundizar en otras funcionalidades</strong> - Explora el capítulo <a href="./../../advanced/">Funciones avanzadas</a>, como gestión de sesiones, sistema de herramientas, etc.</li></ul><div class="tip custom-block"><p class="custom-block-title">Buscar ayuda</p><p>Si encuentras problemas durante el uso, puedes consultar <a href="./../../faq/troubleshooting/">Solución de problemas</a> para obtener soluciones a problemas comunes.</p></div>',26)])])}const f=a(n,[["render",l]]);export{m as __pageData,f as default};
